+    #[test]
+    fn test_prepared_direct_simple_insert_transaction_api_clears_append_hint() {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute(
+            "CREATE TABLE prep_direct_txn_api_hint (id INTEGER PRIMARY KEY, name TEXT NOT NULL);",
+        )
+        .unwrap();
+        let stmt = conn
+            .prepare("INSERT INTO prep_direct_txn_api_hint VALUES (NULL, ?1)")
+            .unwrap();
+
+        conn.begin_transaction().unwrap();
+        stmt.execute_with_params(&[SqliteValue::Text("committed".into())])
+            .unwrap();
+        assert!(
+            conn.prepared_direct_insert_append_hint.borrow().is_some(),
+            "explicit prepared INSERT should retain the append hint while the transaction is open"
+        );
+        conn.commit_transaction().unwrap();
+        assert!(
+            conn.prepared_direct_insert_append_hint.borrow().is_none(),
+            "commit_transaction() bypasses SQL dispatch, so execute_commit_with_cx must clear the append hint itself"
+        );
+
+        conn.begin_transaction().unwrap();
+        stmt.execute_with_params(&[SqliteValue::Text("rolled_back".into())])
+            .unwrap();
+        assert!(
+            conn.prepared_direct_insert_append_hint.borrow().is_some(),
+            "second transaction should rebuild an append hint before rollback"
+        );
+        conn.rollback_transaction().unwrap();
+        assert!(
+            conn.prepared_direct_insert_append_hint.borrow().is_none(),
+            "rollback_transaction() must not leave a hint whose retained leaf image references rolled-back rows"
+        );
+
+        let rows = conn
+            .query("SELECT id, name FROM prep_direct_txn_api_hint ORDER BY id")
+            .unwrap();
+        assert_eq!(
+            rows.iter()
+                .map(|row| row.values().to_vec())
+                .collect::<Vec<_>>(),
+            vec![vec![
+                SqliteValue::Integer(1),
+                SqliteValue::Text("committed".into()),
+            ]],
+        );
+    }
