+    #[test]
+    fn test_prepared_direct_simple_insert_statement_savepoint_rollback_clears_append_hint() {
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute(
+            "CREATE TABLE prep_direct_stmt_sp_hint (id INTEGER PRIMARY KEY, name TEXT NOT NULL);",
+        )
+        .unwrap();
+        let stmt = conn
+            .prepare("INSERT INTO prep_direct_stmt_sp_hint VALUES (NULL, ?1)")
+            .unwrap();
+
+        conn.begin_transaction().unwrap();
+        let err = conn
+            .with_internal_statement_savepoint("append_hint_clear", || -> Result<()> {
+                stmt.execute_with_params(&[SqliteValue::Text("rolled_back".into())])?;
+                assert!(
+                    conn.prepared_direct_insert_append_hint.borrow().is_some(),
+                    "direct prepared INSERT should populate the append hint before the statement savepoint rolls back"
+                );
+                Err(FrankenError::FunctionError(
+                    "forced statement rollback".to_owned(),
+                ))
+            })
+            .expect_err("forced statement error should roll back the internal savepoint");
+        assert!(
+            matches!(err, FrankenError::FunctionError(message) if message == "forced statement rollback")
+        );
+        assert!(
+            conn.prepared_direct_insert_append_hint.borrow().is_none(),
+            "statement-savepoint rollback must clear retained leaf images from the rolled-back B-tree state"
+        );
+
+        let rows = conn
+            .query("SELECT id, name FROM prep_direct_stmt_sp_hint ORDER BY id")
+            .unwrap();
+        assert!(rows.is_empty());
+        conn.rollback_transaction().unwrap();
+    }
